ALTER TABLE policies DROP COLUMN IF EXISTS purpose;
ALTER TABLE policies DROP COLUMN IF EXISTS scope;
ALTER TABLE policies DROP COLUMN IF EXISTS enforcement;
ALTER TABLE policies DROP COLUMN IF EXISTS exceptions;
